// Pricing : 1 paire = 10€, offre 2+1 = 20€ les 3
function calcTotal(n) {
  const sets = Math.floor(n / 3);   // chaque set de 3 = 20€
  const reste = n % 3;              // paires restantes = 10€ chacune
  return sets * 20 + reste * 10;
}
function offreActive(n) { return n >= 3; }
function colorLabel(id) { return COLORIS.find(c => c.id === id)?.label ?? id; }
function colorHex(id)   { return COLORIS.find(c => c.id === id)?.hex  ?? "#ccc"; }
function resumePaires(paires) {
  const counts = {};
  paires.forEach(p => { counts[p.coloris] = (counts[p.coloris] || 0) + 1; });
  return Object.entries(counts).map(([id, n]) => `${n}× ${colorLabel(id)}`).join(", ");
}

