// ─── ATOMS ───────────────────────────────────────────────────────────────────
function Btn({ label, onClick, variant = "primary", style: extra = {}, disabled = false }) {
  const base = { width: "100%", border: "none", borderRadius: 14, padding: "15px 20px", fontSize: 15, fontWeight: 700, cursor: disabled ? "not-allowed" : "pointer", fontFamily: "system-ui", opacity: disabled ? 0.4 : 1, letterSpacing: 0.3 };
  const v = {
    primary:      { background: "#0a0a0a", color: "#fff" },
    white:        { background: "#fff",    color: "#0a0a0a" },
    ghost:        { background: "transparent", color: "#0a0a0a", border: "1.5px solid #0a0a0a" },
    ghost_white:  { background: "transparent", color: "rgba(255,255,255,.45)", border: "1.5px solid rgba(255,255,255,.2)" },
    green:        { background: "#1a7a3a", color: "#fff" },
    danger_ghost: { background: "transparent", color: "#c0392b", border: "1.5px solid #c0392b" },
  };
  return <button style={{ ...base, ...v[variant], ...extra }} onClick={disabled ? undefined : onClick}>{label}</button>;
}

function Field({ label, value, onChange, placeholder, type = "text" }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
      <label style={{ fontSize: 11, fontWeight: 700, color: "#888", fontFamily: "system-ui", textTransform: "uppercase", letterSpacing: 1 }}>{label}</label>
      <input type={type} style={{ border: "1.5px solid #e8e8e8", borderRadius: 12, padding: "13px 14px", fontSize: 15, fontFamily: "system-ui", color: "#0a0a0a", outline: "none", background: "#fafafa" }}
        placeholder={placeholder} value={value} onChange={e => onChange(e.target.value)} />
    </div>
  );
}

function Badge({ statut }) {
  const ok = statut === "payé";
  return <span style={{ padding: "4px 10px", borderRadius: 20, fontSize: 11, fontWeight: 700, fontFamily: "system-ui", background: ok ? "#e8f5e9" : "#fff8e1", color: ok ? "#1a7a3a" : "#c0392b", flexShrink: 0 }}>
    {ok ? "✓ Payé" : "⏳ Attente"}
  </span>;
}

function ColorisPicker({ value, onChange, size = 36 }) {
  return (
    <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
      {COLORIS.map(c => (
        <button key={c.id} onClick={() => onChange(c.id)} title={c.label} style={{
          width: size, height: size, borderRadius: "50%", background: c.hex, cursor: "pointer", flexShrink: 0, border: "none",
          outline: value === c.id ? "3px solid #0a0a0a" : "2px solid transparent",
          outlineOffset: 2,
          boxShadow: (c.hex === "#f5f5f0" || c.hex === "#F5C518") ? "inset 0 0 0 1px rgba(0,0,0,0.15)" : "none",
          transform: value === c.id ? "scale(1.18)" : "scale(1)",
          transition: "all .15s",
        }} />
      ))}
    </div>
  );
}

